import React, { useState } from "react";
import { useTranslation } from "react-i18next";
import { 
  theme, Row, Col, Card, Table, Button, Space, Typography, 
  Input, Form, Select, Divider, Modal, InputNumber, Flex, App
} from "antd";
import { 
  PlusOutlined, SaveOutlined, DeleteOutlined, 
  ExportOutlined, InfoCircleOutlined, SearchOutlined,
  EditOutlined, SyncOutlined
} from "@ant-design/icons";
import dayjs from "dayjs";
import ExcelJS from "exceljs";

const { useToken } = theme;
const { Title, Text } = Typography;

// --- Interfaces ---
interface GroupCodeData { key: string; groupCode: string; groupName: string; sort: number; memo?: string; }
interface CodeDetailData { key: string; groupCode: string; code: string; codeValue: string; sort: number; data1?: string; data2?: string; data3?: string; }

// --- Mock Data ---
const initialGroupCodes: GroupCodeData[] = [
  { key: "1", groupCode: "prj_status", groupName: "Project Status", sort: 1, memo: "" },
  { key: "2", groupCode: "task_status", groupName: "Task Status", sort: 2, memo: "" },
  { key: "3", groupCode: "job_status", groupName: "Job Status", sort: 3, memo: "" },
  { key: "4", groupCode: "user_auth_status", groupName: "Auth Status", sort: 11, memo: "" },
  { key: "5", groupCode: "img_work_status", groupName: "Image Status", sort: 12, memo: "" },
  { key: "6", groupCode: "defect_reason", groupName: "Defect Reason", sort: 21, memo: "Classification for labeling/inspection defects" },
  { key: "10", groupCode: "cam", groupName: "Camera", sort: 51, memo: "" },
];

const initialCodeDetails: CodeDetailData[] = [
  { key: "c1", groupCode: "prj_status", code: "prj_create", codeValue: "Created", sort: 1, data1: "", data2: "", data3: "" },
  { key: "c2", groupCode: "prj_status", code: "prj_cmplt", codeValue: "Completed", sort: 2, data1: "", data2: "", data3: "" },
  { key: "c3", groupCode: "task_status", code: "task_none", codeValue: "Not Started", sort: 1 },
  { key: "c4", groupCode: "task_status", code: "task_ing", codeValue: "In Progress", sort: 2 },
  { key: "dr-1", groupCode: "defect_reason", code: "WRONG_CLASS", codeValue: "Wrong Class", sort: 1 },
  { key: "dr-2", groupCode: "defect_reason", code: "LOOSE_TIGHT", codeValue: "Loose Tightness", sort: 2 },
  { key: "dr-3", groupCode: "defect_reason", code: "MISS_PT", codeValue: "Missed Point", sort: 3 },
  { key: "dr-4", groupCode: "defect_reason", code: "MISS_OBJ", codeValue: "Missed Object", sort: 4 },
  { key: "dr-5", groupCode: "defect_reason", code: "DUP_ANN", codeValue: "Duplicate", sort: 5 },
  { key: "dr-6", groupCode: "defect_reason", code: "OTHER", codeValue: "Other", sort: 6 },
];

export default function ManageCodePage() {
  const { token } = useToken();
  const { t } = useTranslation(["code", "common"]);
  const { message } = App.useApp();

  const [selectedGroup, setSelectedGroup] = useState<string>(initialGroupCodes[0].groupCode);
  const [groupFilter, setGroupFilter] = useState<string>("all");
  const [groupCodes, setGroupCodes] = useState<GroupCodeData[]>(initialGroupCodes);
  const [codeDetails, setCodeDetails] = useState<CodeDetailData[]>(initialCodeDetails);
  const [selectedGKeys, setSelectedGKeys] = useState<React.Key[]>([]);
  const [selectedCKeys, setSelectedCKeys] = useState<React.Key[]>([]);
  const [isGModalOpen, setIsGModalOpen] = useState(false);
  const [isCModalOpen, setIsCModalOpen] = useState(false);
  const [editingG, setEditingG] = useState<GroupCodeData | null>(null);
  const [editingC, setEditingC] = useState<CodeDetailData | null>(null);

  const [gForm] = Form.useForm();
  const [cForm] = Form.useForm();

  const filteredGroupCodes = groupCodes.filter(g => 
    groupFilter === "all" ? true : g.groupCode === groupFilter
  );

  const currentDetails = codeDetails.filter(d => d.groupCode === selectedGroup);

  const handleAddG = () => { setEditingG(null); gForm.resetFields(); setIsGModalOpen(true); };
  const handleEditG = () => {
    const target = groupCodes.find(g => selectedGKeys.includes(g.key));
    if (target) { setEditingG(target); gForm.setFieldsValue(target); setIsGModalOpen(true); }
  };
  const handleDeleteG = () => {
    if (selectedGKeys.length === 0) return message.warning(t("select", { ns: "common" }));
    setGroupCodes(groupCodes.filter(g => !selectedGKeys.includes(g.key)));
    setSelectedGKeys([]);
    message.success(t("delete", { ns: "common" }));
  };

  const handleAddC = () => { setEditingC(null); cForm.resetFields(); setIsCModalOpen(true); };
  const handleEditC = () => {
    const target = codeDetails.find(c => selectedCKeys.includes(c.key));
    if (target) { setEditingC(target); cForm.setFieldsValue(target); setIsCModalOpen(true); }
  };
  const handleDeleteC = () => {
    if (selectedCKeys.length === 0) return message.warning(t("select", { ns: "common" }));
    setCodeDetails(codeDetails.filter(c => !selectedCKeys.includes(c.key)));
    setSelectedCKeys([]);
    message.success(t("delete", { ns: "common" }));
  };

  const handleSaveG = (values: any) => {
    if (editingG) {
      setGroupCodes(groupCodes.map(g => g.key === editingG.key ? { ...g, ...values } : g));
    } else {
      setGroupCodes([...groupCodes, { ...values, key: Date.now().toString() }]);
    }
    setIsGModalOpen(false);
    message.success(t("save", { ns: "common" }));
  };

  const handleSaveC = (values: any) => {
    if (editingC) {
      setCodeDetails(codeDetails.map(c => c.key === editingC.key ? { ...c, ...values } : c));
    } else {
      setCodeDetails([...codeDetails, { ...values, key: Date.now().toString(), groupCode: selectedGroup }]);
    }
    setIsCModalOpen(false);
    message.success(t("save", { ns: "common" }));
  };

  const handleExport = async (type: 'group' | 'code') => {
    const workbook = new ExcelJS.Workbook();
    const sheetName = type === 'group' ? "Groups" : `Codes_${selectedGroup}`;
    const worksheet = workbook.addWorksheet(sheetName);
    
    if (type === 'group') {
      worksheet.columns = [
        { header: t("groupCode"), key: "groupCode", width: 20 },
        { header: t("groupName"), key: "groupName", width: 30 },
        { header: t("sort"), key: "sort", width: 10 },
        { header: t("memo"), key: "memo", width: 40 }
      ];
      groupCodes.forEach(g => worksheet.addRow(g));
    } else {
      worksheet.columns = [
        { header: t("code"), key: "code", width: 20 },
        { header: t("codeValue"), key: "codeValue", width: 30 },
        { header: t("sort"), key: "sort", width: 10 }
      ];
      currentDetails.forEach(c => worksheet.addRow(c));
    }

    const buffer = await workbook.xlsx.writeBuffer();
    const blob = new Blob([buffer], { type: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet" });
    const link = document.createElement("a");
    link.href = window.URL.createObjectURL(blob);
    link.download = `${sheetName}_${dayjs().format("YYYYMMDD")}.xlsx`;
    link.click();
  };

  const sharedCardStyle = { borderRadius: 12, boxShadow: token.boxShadowTertiary, height: "calc(100vh - 180px)" };

  const toolbar = (title: string, onAdd: any, onEdit: any, onDelete: any, onExport: any, hasSelection: boolean) => (
    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
      <Space><InfoCircleOutlined /> <Text strong>{title}</Text></Space>
      <Space size={4}>
        <Button size="small" icon={<PlusOutlined />} onClick={onAdd}>{t("add", { ns: "common" })}</Button>
        <Button size="small" icon={<EditOutlined />} onClick={onEdit} disabled={!hasSelection}>{t("edit", { ns: "common" })}</Button>
        <Button size="small" danger icon={<DeleteOutlined />} onClick={onDelete} disabled={!hasSelection}>{t("delete", { ns: "common" })}</Button>
      </Space>
    </div>
  );

  return (
    <div style={{ padding: "0 24px 24px 24px" }}>
      <div style={{ marginBottom: 16 }}><Title level={4}>{t("title")}</Title></div>

      <div style={{ background: token.colorFillTertiary, padding: "12px 20px", borderRadius: 8, marginBottom: 16 }}>
        <Space size={24}>
          <Space><Text>{t("groupCode")}</Text>
            <Select 
              defaultValue="all" 
              style={{ width: 140 }} 
              size="small" 
              onChange={(v) => {
                setGroupFilter(v);
                if (v !== 'all') setSelectedGroup(v);
              }}
            >
              <Select.Option value="all">{t("total", { ns: "common" })}</Select.Option>
              {groupCodes.map(g => <Select.Option key={g.groupCode} value={g.groupCode}>{g.groupName}</Select.Option>)}
            </Select>
          </Space>
          <Button size="small" icon={<SyncOutlined />}>{t("sync")}</Button>
        </Space>
      </div>

      <Row gutter={16}>
        <Col span={10}>
          <Card title={toolbar(t("groupInfo"), handleAddG, handleEditG, handleDeleteG, () => handleExport('group'), selectedGKeys.length > 0)} variant="borderless" style={sharedCardStyle} styles={{ body: { padding: 0 } }}>
            <Table
              dataSource={filteredGroupCodes} size="small" pagination={false}
              rowSelection={{ type: "checkbox", selectedRowKeys: selectedGKeys, onChange: (keys) => setSelectedGKeys(keys) }}
              onRow={(record) => ({ onClick: () => { setSelectedGroup(record.groupCode); setSelectedGKeys([record.key]); }, style: { cursor: "pointer", background: selectedGroup === record.groupCode ? token.colorPrimaryBg : "transparent" } })}
              scroll={{ y: "calc(100vh - 350px)" }}
              locale={{ emptyText: t("noObjects", { ns: "common" }) }}
              columns={[
                { title: t("groupCode"), dataIndex: "groupCode", key: "gcode", width: "30%" },
                { title: t("groupName"), dataIndex: "groupName", key: "gname" },
                { title: t("sort"), dataIndex: "sort", key: "sort", width: 60, align: "center" },
              ]}
            />
          </Card>
        </Col>

        <Col span={14}>
          <Card title={toolbar(t("codeInfo"), handleAddC, handleEditC, handleDeleteC, () => handleExport('code'), selectedCKeys.length > 0)} variant="borderless" style={sharedCardStyle} styles={{ body: { padding: 0 } }}>
            <Table
              dataSource={currentDetails} size="small" pagination={false}
              rowSelection={{ type: "checkbox", selectedRowKeys: selectedCKeys, onChange: (keys) => setSelectedCKeys(keys) }}
              onRow={(record) => ({ onClick: () => setSelectedCKeys([record.key]), style: { cursor: "pointer" } })}
              scroll={{ y: "calc(100vh - 350px)" }}
              locale={{ emptyText: t("noObjects", { ns: "common" }) }}
              columns={[
                { title: t("code"), dataIndex: "code", key: "code", width: "25%" },
                { title: t("codeValue"), dataIndex: "codeValue", key: "val" },
                { title: t("sort"), dataIndex: "sort", key: "sort", width: 60, align: "center" },
                { title: t("data1"), dataIndex: "data1", key: "d1" },
              ]}
            />
          </Card>
        </Col>
      </Row>

      <Modal title={editingG ? t("edit", { ns: "common" }) : t("add", { ns: "common" })} open={isGModalOpen} onCancel={() => setIsGModalOpen(false)} onOk={() => gForm.submit()} destroyOnHidden centered>
        <Form form={gForm} layout="vertical" onFinish={handleSaveG} style={{ marginTop: 16 }}>
          <Form.Item name="groupCode" label={t("groupCode")} rules={[{ required: true }]}><Input /></Form.Item>
          <Form.Item name="groupName" label={t("groupName")} rules={[{ required: true }]}><Input /></Form.Item>
          <Form.Item name="sort" label={t("sort")} initialValue={1}><InputNumber style={{width: '100%'}} /></Form.Item>
          <Form.Item name="memo" label={t("memo")}><Input.TextArea rows={3} /></Form.Item>
        </Form>
      </Modal>

      <Modal title={editingC ? t("edit", { ns: "common" }) : t("add", { ns: "common" })} open={isCModalOpen} onCancel={() => setIsCModalOpen(false)} onOk={() => cForm.submit()} destroyOnHidden centered>
        <Form form={cForm} layout="vertical" onFinish={handleSaveC} style={{ marginTop: 16 }}>
          <Form.Item label={t("groupCode")}><Input value={selectedGroup} disabled /></Form.Item>
          <Form.Item name="code" label={t("code")} rules={[{ required: true }]}><Input /></Form.Item>
          <Form.Item name="codeValue" label={t("codeValue")} rules={[{ required: true }]}><Input /></Form.Item>
          <Form.Item name="sort" label={t("sort")} initialValue={1}><InputNumber style={{width: '100%'}} /></Form.Item>
          <Form.Item name="data1" label={t("data1")}><Input /></Form.Item>
        </Form>
      </Modal>
    </div>
  );
}
